import React, { useState, useEffect, useContext, useCallback } from 'react';
import {
  Box, Container, Typography, Card, CardContent, Grid,
  Table, TableBody, TableCell, TableContainer, TableHead, TableRow,
  Paper, Chip, Avatar, IconButton, Tooltip, TextField, InputAdornment,
  Select, MenuItem, FormControl, InputLabel, Button, Dialog, DialogTitle,
  DialogContent, DialogActions, List, ListItem, ListItemText, Divider,
  Alert, CircularProgress, Badge, AppBar, Toolbar, Menu
} from '@mui/material';
import {
  Search, FilterList, Person, Email, TrendingUp, TrendingDown,
  Close, Visibility, AdminPanelSettings, CheckCircle, Cancel, 
  AccountCircle, Settings, Security, ShowChart, LocalAtmRounded,
  CloseOutlined, Logout, Dashboard, PeopleAlt, PersonAdd, 
  VerifiedUser, Block, RefreshRounded, AttachMoney, BarChart,
  History, Assessment, SupervisorAccount, LockReset, MoreVert,
  Timeline, Analytics, TrendingUpOutlined, AccountBalance
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { AuthContext } from '../../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import OpenOrdersCard from './OpenOrdersCard';

const AdminDashboard = () => {
  console.log('AdminDashboard: Componente carregando...');
  
  const { logout } = useContext(AuthContext);
  const navigate = useNavigate();
  
  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isAutoUpdating, setIsAutoUpdating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [systemStats, setSystemStats] = useState(null);
  const [tradesOverview, setTradesOverview] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userMenuAnchor, setUserMenuAnchor] = useState(null);
  const [resetPasswordDialog, setResetPasswordDialog] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [showSystemStats, setShowSystemStats] = useState(false);
  const [showTradesOverview, setShowTradesOverview] = useState(false);
  const [stats, setStats] = useState({
    total_users: 0,
    active_users: 0,
    inactive_users: 0,
    admin_users: 0,
    total_under_management_usd: 0,
    open_positions: {
      positive_count: 0,
      negative_count: 0,
      total_roe_percentage: 0
    }
  });

  useEffect(() => {
    console.log('AdminDashboard: useEffect inicial - carregando dados...');
    fetchAdminData();
  }, []);

  useEffect(() => {
    console.log('AdminDashboard: Filtrando usuários...');
    filterUsers();
  }, [users, searchTerm, statusFilter]);

  // Auto-atualização a cada 30 segundos
  useEffect(() => {
    const interval = setInterval(async () => {
      console.log('🔄 [AUTO-UPDATE] Atualizando dados admin silenciosamente...');
      setIsAutoUpdating(true);
      await fetchAdminData(false); // Carregamento silencioso
      setTimeout(() => setIsAutoUpdating(false), 1000);
    }, 30000);

    return () => clearInterval(interval);
  }, []);

  const fetchAdminData = useCallback(async (showLoading = true) => {
    if (showLoading) setLoading(true);
    try {
      const [usersResponse, statsResponse] = await Promise.all([
        fetch('/api/admin/users', { credentials: 'include' }),
        fetch('/api/admin/dashboard/stats', { credentials: 'include' })
      ]);

      if (!usersResponse.ok || !statsResponse.ok) {
        throw new Error('Falha ao carregar dados do administrador.');
      }

      const usersData = await usersResponse.json();
      const statsData = await statsResponse.json();

      setUsers(usersData.users || []);
      setStats({
        total_users: usersData.summary?.total_users || 0,
        active_users: usersData.summary?.active_users || 0,
        inactive_users: usersData.summary?.inactive_users || 0,
        total_under_management_usd: statsData.total_under_management_usd || 0,
        open_positions: statsData.open_positions || {
          positive_count: 0,
          negative_count: 0,
          total_roe_percentage: 0
        }
      });

    } catch (error) {
      console.error("Erro ao carregar dados do admin:", error);
      toast.error(error.message || 'Erro ao carregar dados.');
    } finally {
      if (showLoading) setLoading(false);
    }
  }, []);

  const filterUsers = () => {
    let filtered = users;

    // Filtro de busca
    if (searchTerm) {
      filtered = filtered.filter(user =>
        user.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Filtro de status
    if (statusFilter !== 'all') {
      filtered = filtered.filter(user => {
        if (statusFilter === 'active') return user.is_active;
        if (statusFilter === 'inactive') return !user.is_active;
        if (statusFilter === 'admin') return user.is_admin;
        return true;
      });
    }

    setFilteredUsers(filtered);
  };

  const handleUserClick = (user) => {
    console.log(`AdminDashboard: Navegando para o dashboard do usuário: ${user.full_name}`);
    navigate(`/admin/user/${user.id}`);
  };

  const handleToggleNautilusStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-nautilus-status`, {
        method: 'POST',
        credentials: 'include'
      });
      const data = await response.json();
      if (response.ok) {
        toast.success(data.message);
        fetchAdminData(false);
      } else {
        toast.error(data.message);
      }
    } catch (error) {
      toast.error('Erro ao alterar status Nautilus.');
    }
  };

  const handleToggleUserStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-status`, {
        method: 'POST',
        credentials: 'include'
      });
      if (response.ok) {
        toast.success('Status do usuário atualizado.');
        fetchAdminData(false);
      } else {
        toast.error('Erro ao atualizar status do usuário.');
      }
    } catch (error) {
      toast.error('Erro ao atualizar status.');
    }
  };

  const fetchSystemStats = async () => {
    try {
      const response = await fetch('/api/admin/system/stats', { credentials: 'include' });
      if (response.ok) {
        const data = await response.json();
        setSystemStats(data);
        setShowSystemStats(true);
      } else {
        toast.error('Erro ao carregar estatísticas do sistema.');
      }
    } catch (error) {
      toast.error('Erro ao carregar estatísticas do sistema.');
    }
  };

  const fetchTradesOverview = async () => {
    try {
      const response = await fetch('/api/admin/trades/overview', { credentials: 'include' });
      if (response.ok) {
        const data = await response.json();
        setTradesOverview(data);
        setShowTradesOverview(true);
      } else {
        toast.error('Erro ao carregar visão geral de trades.');
      }
    } catch (error) {
      toast.error('Erro ao carregar visão geral de trades.');
    }
  };

  const handleUserMenuClick = (event, user) => {
    event.stopPropagation();
    setSelectedUser(user);
    setUserMenuAnchor(event.currentTarget);
  };

  const handleUserMenuClose = () => {
    setUserMenuAnchor(null);
    setSelectedUser(null);
  };

  const handleResetPassword = async () => {
    if (!newPassword || newPassword.length < 6) {
      toast.error('A senha deve ter pelo menos 6 caracteres.');
      return;
    }

    try {
      const response = await fetch(`/api/admin/user/${selectedUser.id}/reset-password`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ new_password: newPassword })
      });

      const data = await response.json();
      if (response.ok) {
        toast.success(data.message);
        setResetPasswordDialog(false);
        setNewPassword('');
        handleUserMenuClose();
      } else {
        toast.error(data.message);
      }
    } catch (error) {
      toast.error('Erro ao resetar senha.');
    }
  };

  const handleToggleAdminStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-admin`, {
        method: 'POST',
        credentials: 'include'
      });

      const data = await response.json();
      if (response.ok) {
        toast.success(data.message);
        fetchAdminData(false);
        handleUserMenuClose();
      } else {
        toast.error(data.message);
      }
    } catch (error) {
      toast.error('Erro ao alterar status de administrador.');
    }
  };

  const handleViewUserTrades = (userId) => {
    navigate(`/admin/user/${userId}/trades`);
  };

  const handleViewUserStats = (userId) => {
    navigate(`/admin/user/${userId}/stats`);
  };

  // Função para navegar para o dashboard de usuário
  const handleGoToUserDashboard = () => {
    console.log('AdminDashboard: Navegando para dashboard de usuário');
    navigate('/dashboard');
  };

  // Função para fazer logout
  const handleLogout = async () => {
    console.log('AdminDashboard: Logout');
    await logout();
    navigate('/login');
  };

  const getStatusColor = (isActive) => {
    return isActive ? 'success' : 'error';
  };

  const getStatusText = (isActive) => {
    return isActive ? 'Ativo' : 'Inativo';
  };

  const getPnlColor = (pnl) => {
    if (pnl > 0) return 'success.main';
    if (pnl < 0) return 'error.main';
    return 'text.secondary';
  };

  const formatUsd = (value, fractionDigits = 2) => {
    const num = Number(value);
    return isNaN(num) ? '$0.00' : num.toLocaleString('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: fractionDigits,
      maximumFractionDigits: fractionDigits
    });
  };
  
  const formatPercentage = (value) => {
    return `${(value || 0).toFixed(4)}%`;
  }

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1, bgcolor: '#1a1a1a' }}>
        <Toolbar>
          <AdminPanelSettings sx={{ mr: 2, fontSize: 30, color: '#f0b90b' }} />
          <Box sx={{ flexGrow: 1, display: 'flex', alignItems: 'center', gap: 2 }}>
            <Typography variant="h6" noWrap component="div" sx={{ color: '#f0b90b' }}>
              Admin Dashboard
            </Typography>
            <Chip 
              label="Modo Administrador" 
              color="warning"
              size="small"
              sx={{ 
                fontWeight: 'bold',
                bgcolor: '#ff6b35',
                color: 'white',
                '& .MuiChip-label': {
                  fontSize: '0.75rem'
                }
              }}
            />
          </Box>
          {isAutoUpdating && <CircularProgress size={24} color="inherit" />}
          <Tooltip title="Ver Dashboard de Usuário">
            <IconButton onClick={handleGoToUserDashboard} color="inherit">
              <Dashboard />
            </IconButton>
          </Tooltip>
          <Tooltip title="Estatísticas do Sistema">
            <IconButton onClick={fetchSystemStats} color="inherit">
              <Analytics />
            </IconButton>
          </Tooltip>
          <Tooltip title="Visão Geral de Trades">
            <IconButton onClick={fetchTradesOverview} color="inherit">
              <Assessment />
            </IconButton>
          </Tooltip>
          <Tooltip title="Atualizar Dados">
            <IconButton onClick={() => fetchAdminData(true)} color="inherit">
              <RefreshRounded />
            </IconButton>
          </Tooltip>
          <Tooltip title="Sair">
            <IconButton onClick={handleLogout} color="inherit">
              <Logout />
            </IconButton>
          </Tooltip>
        </Toolbar>
      </AppBar>
      
      <Box component="main" sx={{ flexGrow: 1, p: 3, bgcolor: '#121212', minHeight: '100vh', mt: '64px' }}>
        <Container maxWidth="xl" sx={{ mt: 4, mb: 4 }}>
          {loading && <CircularProgress sx={{ display: 'block', margin: 'auto' }} />}
          
          <Grid container spacing={3}>
            {/* Novo Card de Ordens Abertas */}
            <Grid item xs={12} sm={6} md={3}>
              <OpenOrdersCard stats={stats} />
            </Grid>
            
            {/* Card de Valor Sob Gestão */}
            <Grid item xs={12} sm={6} md={3}>
              <Card sx={{ bgcolor: 'primary.main', color: 'white', height: '100%' }}>
                <CardContent>
                  <Typography variant="h6" gutterBottom>Valor Sob Gestão (USD)</Typography>
                  <Box sx={{ display: 'flex', alignItems: 'center', mt: 2 }}>
                    <AttachMoney sx={{ fontSize: 40, mr: 2 }} />
                    <Typography variant="h4">
                      {formatUsd(stats.total_under_management_usd)}
                    </Typography>
                  </Box>
                </CardContent>
              </Card>
            </Grid>

            {/* Cards de contagem de usuários agrupados */}
            <Grid item xs={12} md={6}>
              <Grid container spacing={2}>
                <Grid item xs={12} sm={4}>
                  <Card sx={{ bgcolor: '#424242', color: 'white', height: '100%', textAlign: 'center' }}>
                    <CardContent>
                      <Typography>Total</Typography>
                      <Typography variant="h4">{stats.total_users}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} sm={4}>
                  <Card sx={{ bgcolor: 'success.dark', color: 'white', height: '100%', textAlign: 'center' }}>
                    <CardContent>
                      <Typography>Ativos</Typography>
                      <Typography variant="h4">{stats.active_users}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} sm={4}>
                  <Card sx={{ bgcolor: 'error.dark', color: 'white', height: '100%', textAlign: 'center' }}>
                    <CardContent>
                      <Typography>Inativos</Typography>
                      <Typography variant="h4">{stats.inactive_users}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
              </Grid>
            </Grid>
          </Grid>

          {/* Tabela de Usuários */}
          <Card sx={{ mt: 4, borderRadius: 3, boxShadow: '0 8px 32px 0 rgba(31, 38, 135, 0.37)' }}>
            <CardContent>
              {/* Cabeçalho da Tabela e Filtros */}
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2, flexWrap: 'wrap', gap: 2 }}>
                <Typography variant="h6">Usuários</Typography>
                <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
                  <TextField
                    label="Buscar Usuário"
                    variant="outlined"
                    size="small"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <Search />
                        </InputAdornment>
                      ),
                    }}
                  />
                  <FormControl variant="outlined" size="small" sx={{ minWidth: 120 }}>
                    <InputLabel>Status</InputLabel>
                    <Select
                      value={statusFilter}
                      onChange={(e) => setStatusFilter(e.target.value)}
                      label="Status"
                    >
                      <MenuItem value="all">Todos</MenuItem>
                      <MenuItem value="active">Ativos</MenuItem>
                      <MenuItem value="inactive">Inativos</MenuItem>
                      <MenuItem value="admin">Admins</MenuItem>
                    </Select>
                  </FormControl>
                  <Tooltip title="Atualizar Dados">
                    <span>
                      <IconButton onClick={() => fetchAdminData()} color="primary" disabled={loading}>
                        {loading ? <CircularProgress size={24} /> : <RefreshRounded />}
                      </IconButton>
                    </span>
                  </Tooltip>
                </Box>
              </Box>

              {/* Tabela */}
              <TableContainer component={Paper} sx={{ borderRadius: 2 }}>
                <Table stickyHeader aria-label="users table">
                  <TableHead>
                    <TableRow>
                      <TableCell sx={{ fontWeight: 'bold' }}>Usuário</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Status</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Último Login</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Total de Trades</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Total PNL (USD)</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Total sob Gestão (USD)</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Status Nautilus</TableCell>
                      <TableCell align="center" sx={{ fontWeight: 'bold' }}>Ações</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {loading ? (
                      <TableRow>
                        <TableCell colSpan={8} align="center">
                          <CircularProgress />
                        </TableCell>
                      </TableRow>
                    ) : filteredUsers.length > 0 ? (
                      filteredUsers.map((user) => (
                        <TableRow key={user.id} hover sx={{ '&:last-child td, &:last-child th': { border: 0 } }}>
                          <TableCell>
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              <Avatar sx={{ bgcolor: getStatusColor(user.is_active), width: 32, height: 32, mr: 1.5 }}>
                                <Person sx={{ fontSize: '1rem' }} />
                              </Avatar>
                              <Box>
                                <Typography variant="body2" fontWeight="bold">{user.full_name}</Typography>
                                <Typography variant="caption" color="text.secondary">{user.email}</Typography>
                              </Box>
                            </Box>
                          </TableCell>
                          <TableCell align="center">
                            <Tooltip title={user.is_active ? 'Usuário Ativo' : 'Usuário Inativo'}>
                              <Chip 
                                label={getStatusText(user.is_active)}
                                color={getStatusColor(user.is_active)}
                                size="small"
                              />
                            </Tooltip>
                          </TableCell>
                          <TableCell align="center">
                            <Typography variant="body2">{formatDate(user.last_login)}</Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Typography variant="body2">{user.total_trades || 0}</Typography>
                          </TableCell>
                          <TableCell align="center" sx={{ color: getPnlColor(user.total_pnl), fontWeight: 'medium' }}>
                            <Typography variant="body2" sx={{color: getPnlColor(user.total_pnl)}}>
                              {formatUsd(user.total_pnl, 2)}
                            </Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Typography variant="body2">
                              {formatUsd(user.balance_usd, 2)}
                            </Typography>
                          </TableCell>
                          <TableCell align="center">
                            <Chip 
                              icon={user.nautilus_active ? <CheckCircle /> : <Cancel />}
                              label={user.nautilus_active ? 'Ativo' : 'Inativo'}
                              color={user.nautilus_active ? 'success' : 'error'}
                              variant="outlined"
                              size="small"
                              onClick={(e) => {
                                e.stopPropagation();
                                handleToggleNautilusStatus(user.id);
                              }}
                              sx={{ cursor: 'pointer' }}
                            />
                          </TableCell>
                          <TableCell align="center">
                            <Box sx={{ display: 'flex', gap: 1, justifyContent: 'center' }}>
                              <Tooltip title="Ver Dashboard">
                                <IconButton 
                                  size="small" 
                                  onClick={() => navigate(`/admin/user/${user.id}/dashboard`)}
                                  sx={{ color: 'primary.main' }}
                                >
                                  <Visibility />
                                </IconButton>
                              </Tooltip>
                              <Tooltip title="Histórico de Trades">
                                <IconButton 
                                  size="small" 
                                  onClick={() => handleViewUserTrades(user.id)}
                                  sx={{ color: 'info.main' }}
                                >
                                  <History />
                                </IconButton>
                              </Tooltip>
                              <Tooltip title="Estatísticas Detalhadas">
                                <IconButton 
                                  size="small" 
                                  onClick={() => handleViewUserStats(user.id)}
                                  sx={{ color: 'warning.main' }}
                                >
                                  <Timeline />
                                </IconButton>
                              </Tooltip>
                              <Tooltip title="Mais Opções">
                                <IconButton 
                                  size="small" 
                                  onClick={(e) => handleUserMenuClick(e, user)}
                                  sx={{ color: 'text.secondary' }}
                                >
                                  <MoreVert />
                                </IconButton>
                              </Tooltip>
                            </Box>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell align="center" colSpan={8}>
                          <Typography variant="body1" sx={{ p: 2 }}>Nenhum usuário encontrado</Typography>
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </TableContainer>
            </CardContent>
          </Card>
        </Container>

        {/* Menu de Ações do Usuário */}
        <Menu
          anchorEl={userMenuAnchor}
          open={Boolean(userMenuAnchor)}
          onClose={handleUserMenuClose}
          PaperProps={{
            sx: { minWidth: 200 }
          }}
        >
          <MenuItem onClick={() => handleToggleUserStatus(selectedUser?.id)}>
            {selectedUser?.is_active ? <Block sx={{ mr: 1 }} /> : <CheckCircle sx={{ mr: 1 }} />}
            {selectedUser?.is_active ? 'Desativar Usuário' : 'Ativar Usuário'}
          </MenuItem>
          <MenuItem onClick={() => handleToggleAdminStatus(selectedUser?.id)}>
            <SupervisorAccount sx={{ mr: 1 }} />
            {selectedUser?.is_admin ? 'Remover Admin' : 'Tornar Admin'}
          </MenuItem>
          <MenuItem onClick={() => { setResetPasswordDialog(true); handleUserMenuClose(); }}>
            <LockReset sx={{ mr: 1 }} />
            Resetar Senha
          </MenuItem>
        </Menu>

        {/* Diálogo de Reset de Senha */}
        <Dialog open={resetPasswordDialog} onClose={() => setResetPasswordDialog(false)}>
          <DialogTitle>Resetar Senha do Usuário</DialogTitle>
          <DialogContent>
            <Typography sx={{ mb: 2 }}>
              Digite a nova senha para {selectedUser?.full_name}:
            </Typography>
            <TextField
              autoFocus
              margin="dense"
              label="Nova Senha"
              type="password"
              fullWidth
              variant="outlined"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              sx={{ mt: 2 }}
            />
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setResetPasswordDialog(false)}>Cancelar</Button>
            <Button onClick={handleResetPassword} variant="contained">Resetar</Button>
          </DialogActions>
        </Dialog>

        {/* Diálogo de Estatísticas do Sistema */}
        <Dialog 
          open={showSystemStats} 
          onClose={() => setShowSystemStats(false)}
          maxWidth="md"
          fullWidth
        >
          <DialogTitle>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <Analytics />
              Estatísticas do Sistema
            </Box>
          </DialogTitle>
          <DialogContent>
            {systemStats && (
              <Grid container spacing={3}>
                <Grid item xs={12} md={6}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>
                        <PeopleAlt sx={{ mr: 1, verticalAlign: 'middle' }} />
                        Usuários
                      </Typography>
                      <Typography>Total: {systemStats.users?.total || 0}</Typography>
                      <Typography>Ativos: {systemStats.users?.active || 0}</Typography>
                      <Typography>Administradores: {systemStats.users?.admins || 0}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} md={6}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>
                        <BarChart sx={{ mr: 1, verticalAlign: 'middle' }} />
                        Trades
                      </Typography>
                      <Typography>Total: {systemStats.trades?.total || 0}</Typography>
                      <Typography>Abertos: {systemStats.trades?.open || 0}</Typography>
                      <Typography>Fechados: {systemStats.trades?.closed || 0}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>
                        <AccountBalance sx={{ mr: 1, verticalAlign: 'middle' }} />
                        Financeiro
                      </Typography>
                      <Typography>PnL Total: {formatUsd(systemStats.financial?.total_pnl || 0)}</Typography>
                      <Typography>Valor Sob Gestão: {formatUsd(systemStats.financial?.total_aum || 0)}</Typography>
                      <Typography>Taxa de Vitória: {formatPercentage(systemStats.financial?.win_rate || 0)}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
              </Grid>
            )}
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setShowSystemStats(false)}>Fechar</Button>
          </DialogActions>
        </Dialog>

        {/* Diálogo de Visão Geral de Trades */}
        <Dialog 
          open={showTradesOverview} 
          onClose={() => setShowTradesOverview(false)}
          maxWidth="lg"
          fullWidth
        >
          <DialogTitle>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <Assessment />
              Visão Geral de Trades
            </Box>
          </DialogTitle>
          <DialogContent>
            {tradesOverview && (
              <Grid container spacing={3}>
                <Grid item xs={12} md={4}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>Estatísticas Gerais</Typography>
                      <Typography>Total de Trades: {tradesOverview.general_stats?.total_trades || 0}</Typography>
                      <Typography>PnL Realizado: {formatUsd(tradesOverview.general_stats?.total_realized_pnl || 0)}</Typography>
                      <Typography>Trades Vencedores: {tradesOverview.general_stats?.winning_trades || 0}</Typography>
                      <Typography>Taxa de Vitória: {formatPercentage(tradesOverview.general_stats?.win_rate || 0)}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} md={4}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>Top Símbolos</Typography>
                      {tradesOverview.top_symbols?.map((symbol, index) => (
                        <Typography key={index}>
                          {symbol.symbol}: {symbol.count} trades
                        </Typography>
                      ))}
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} md={4}>
                  <Card>
                    <CardContent>
                      <Typography variant="h6" gutterBottom>Usuários Mais Ativos</Typography>
                      {tradesOverview.top_users?.map((user, index) => (
                        <Typography key={index}>
                          {user.username}: {user.trade_count} trades
                        </Typography>
                      ))}
                    </CardContent>
                  </Card>
                </Grid>
              </Grid>
            )}
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setShowTradesOverview(false)}>Fechar</Button>
          </DialogActions>
        </Dialog>
      </Box>
    </Box>
  );
};

export default AdminDashboard;
